import{_ as l,o as s,c as t,ag as i}from"./chunks/framework.eQLvDOR_.js";const h=JSON.parse('{"title":"2026-04-04-skills-vs-mcp","description":"","frontmatter":{"title":"2026-04-04-skills-vs-mcp","question":"skills有什么用，和mcp有什么区别","answer_summary":"MCP 提供底层的数据/工具连接能力（手和眼睛），而 Skills 提供基于这些工具的上层领域知识与业务流程设计（大脑与经验）。两者是组合互补关系。","sources":["02_Library/ADK_Agent_Skills/[ADK_Agent_Skills] ADK-Agent-Skills-Progressive-Disclosure-with-SkillToolset-(Part-1).md","02_Library/NotebookLM_Workflows/[NotebookLM_Workflows] Integrate-NotebookLM-with-Gemini-CLI,-Google-Antigravity-or-Other-Agents-with-MCP.md","03_Wiki/concepts/skill-design-patterns.md"],"created_at":"2026-04-04"},"headers":[],"relativePath":"wiki/questions/2026-04-04-skills-vs-mcp.md","filePath":"wiki/questions/2026-04-04-skills-vs-mcp.md","lastUpdated":null}'),o={name:"wiki/questions/2026-04-04-skills-vs-mcp.md"};function a(r,e,n,c,d,k){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="q-skills-有什么用-和-mcp-有什么区别" tabindex="-1">Q: Skills 有什么用，和 MCP 有什么区别？ <a class="header-anchor" href="#q-skills-有什么用-和-mcp-有什么区别" aria-label="Permalink to &quot;Q: Skills 有什么用，和 MCP 有什么区别？&quot;">​</a></h1><h2 id="简短回答" tabindex="-1">简短回答 <a class="header-anchor" href="#简短回答" aria-label="Permalink to &quot;简短回答&quot;">​</a></h2><ul><li><strong>MCP (Model Context Protocol)</strong> 是 <strong>骨骼与肌肉（行动/数据层）</strong>：它为 Agent 提供标准化的外部工具调用接口（如查数据库、调 API）。</li><li><strong>Agent Skills (技能)</strong> 是 <strong>大脑与经验（知识/工作流层）</strong>：它按需为 Agent 注入领域知识、操作规范和固定的业务逻辑。</li></ul><p>两者是互补协作关系：MCP 提供原子化能力，Skills 决定如何优雅地调度这些能力。</p><h2 id="详细分析" tabindex="-1">详细分析 <a class="header-anchor" href="#详细分析" aria-label="Permalink to &quot;详细分析&quot;">​</a></h2><h3 id="何为-mcp" tabindex="-1">何为 MCP？ <a class="header-anchor" href="#何为-mcp" aria-label="Permalink to &quot;何为 MCP？&quot;">​</a></h3><p>MCP 被形容为“AI 界应用连接的 USB-C 接口”。它的核心目的是解决 <code>M*N</code> 的多对多直连问题。一旦为某个服务（例如 NotebookLM、GitHub、天气 API）编写了 MCP server，那么任何支持 MCP 协议的 Agent (如 Antigravity, Gemini CLI) 都可以无缝挂载它们，从而获得了<strong>执行</strong>这类动作的“接口”权益。</p><h3 id="何为-skills" tabindex="-1">何为 Skills？ <a class="header-anchor" href="#何为-skills" aria-label="Permalink to &quot;何为 Skills？&quot;">​</a></h3><p>Agent Skills 是解决<strong>上下文疲劳</strong>与<strong>能力注入</strong>的轻量级解决方案。相比于在 System Prompt 当中塞入巨量的业务规范文档（容易让模型注意力涣散并消耗极多 Tokens），大模型在识别到某个业务意图后，通过工具系统临时装载指定的 <code>SKILL.md</code>，获得<strong>如何执行</strong>这个任务的“步骤经验”。</p><h3 id="工作流实战案例-东京旅游规划" tabindex="-1">工作流实战案例：东京旅游规划 <a class="header-anchor" href="#工作流实战案例-东京旅游规划" aria-label="Permalink to &quot;工作流实战案例：东京旅游规划&quot;">​</a></h3><ol><li><strong>Agent Skills (制定策略)</strong>：系统挂载 <code>travel-planner</code> Skill，该 Skill 告诉 Agent：&quot;第一步查天气，第二步定路线，第三步生成 Markdown 表格。&quot;</li><li><strong>MCP (执行动作)</strong>：Agent 通过内置的 <code>Weather-API-MCP</code> 发起真实的外部请求，拿到东京的实时温度。</li><li><strong>闭环</strong>：Agent 根据天气的返回事实（MCP 提供），再依据制表约束（Skill 提供），将正确的答案呈递给用户。</li></ol><h2 id="相关概念" tabindex="-1">相关概念 <a class="header-anchor" href="#相关概念" aria-label="Permalink to &quot;相关概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/skill-design-patterns.html">skill-design-patterns</a></li><li><a href="/s/webclips/wiki/concepts/progressive-disclosure.html">progressive-disclosure</a></li><li><a href="/s/webclips/wiki/connections/knowledge-compilation-vs-rag.html">knowledge-compilation-vs-rag</a></li></ul>',13)])])}const p=l(o,[["render",a]]);export{h as __pageData,p as default};
